#include <bits/stdc++.h>
using namespace std;

int a[210], b[210];

int pvp(int a, int b) {
    if(a == 0 && b == 0) return -1;
    else if(a == 0 && b == 1) return 0;
    else if(a == 0 && b == 2) return 1;
    else if(a == 0 && b == 3) return 1;
    else if(a == 0 && b == 4) return 0;

    else if(a == 1 && b == 0) return 1;
    else if(a == 1 && b == 1) return -1;
    else if(a == 1 && b == 2) return 0;
    else if(a == 1 && b == 3) return 1;
    else if(a == 1 && b == 4) return 0;

    else if(a == 2 && b == 0) return 0;
    else if(a == 2 && b == 1) return 1;
    else if(a == 2 && b == 2) return -1;
    else if(a == 2 && b == 3) return 0;
    else if(a == 2 && b == 4) return 1;

    else if(a == 3 && b == 0) return 0;
    else if(a == 3 && b == 1) return 0;
    else if(a == 3 && b == 2) return 1;
    else if(a == 3 && b == 3) return -1;
    else if(a == 3 && b == 4) return 1;

    else if(a == 4 && b == 0) return 1;
    else if(a == 4 && b == 1) return 1;
    else if(a == 4 && b == 2) return 0;
    else if(a == 4 && b == 3) return 0;
    else if(a == 4 && b == 4) return -1;
}


int main() {
    int n, na, nb;
    cin >> n >> na >> nb;
    for(int i = 0; i < na; i++) {
        cin >> a[i];
    }
    for(int i = 0; i < nb; i++) {
        cin >> b[i];
    }
    int asc = 0, bsc = 0;
    int anow = 0, bnow = 0;
    for(int i = 0,ai=0,bi=0; i < n; i++,ai++,bi++) {
        if(ai==na) ai=0;
        if(bi==nb) bi=0;
        anow=a[ai];
        bnow=b[bi];

        if(pvp(anow, bnow) == 0) bsc++;
        else if(pvp(anow, bnow) == 1) asc++;
        anow++, bnow++, anow %= na, bnow %= nb;
    }
    cout << asc << " " << bsc << endl;

}
